package atest;

import java.awt.image.BufferedImage;
import java.io.ByteArrayInputStream;
import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.util.Base64;

import javax.imageio.ImageIO;

public class Base64ToPngConverter {

    public static void main(String[] args) throws IOException {
     
    	 String base64DataUrl = 
    			 "data:image/png;base64,";
         
    	 byte[] imgInBytes = Base64.getDecoder().decode(base64DataUrl);
    	 InputStream in = new ByteArrayInputStream(imgInBytes);
    	 BufferedImage bufferedImage = ImageIO.read(in);
    	 File png = new File("/home/tischer/ImageAsPNG.png");
    	 ImageIO.write(bufferedImage, "PNG", png);
     
    	
    }
}